#[tokio::test]
async fn test_anthropic_chat() {
    // Basic chat completion via the Anthropic provider (claude-3-5-sonnet-20241022) with system and user messages
    let mock_route = MockRoute {
        path: "/chat/completions",
        method: "POST",
        status: 200,
        body: r#"{"choices":[{"finish_reason":"stop","index":0,"message":{"content":"Hello!","role":"assistant"}}],"created":1711000100,"id":"chatcmpl-anthropic-001","model":"claude-3-5-sonnet-20241022","object":"chat.completion","usage":{"completion_tokens":3,"prompt_tokens":20,"total_tokens":23}}"#.to_string(),
        is_streaming: false,
        stream_chunks: vec![],
        headers: vec![
        ],
        delay_ms: None,
    };
    let mock_server = MockServer::start(vec![mock_route]).await;
    let request_json: serde_json::Value = serde_json::from_str(r#"{"max_tokens":16,"messages":[{"content":"You are a helpful assistant.","role":"system"},{"content":"Say hello in one word.","role":"user"}],"model":"anthropic/claude-3-5-sonnet-20241022","temperature":0}"#).unwrap();
    let request = serde_json::from_value(request_json).unwrap();
    let client =
        liter_llm::create_client("test-key".to_string(), Some(mock_server.url.clone()), None, None, None).unwrap();
    let result = client.chat(request).await.expect("should succeed");
    let _choices_0_message_content = result.choices[0]
        .message
        .content
        .as_ref()
        .map(|v| v.to_string())
        .unwrap_or_default();
    let _choices_0_finish_reason = result.choices[0]
        .finish_reason
        .as_ref()
        .map(|v| v.to_string())
        .unwrap_or_default();
    assert_eq!(
        result.choices.len(),
        1,
        "expected exactly 1 elements, got {}",
        result.choices.len()
    );
    assert_eq!(
        _choices_0_message_content.to_string().as_str().trim(),
        r#"Hello!"#,
        "equals assertion failed"
    );
    assert_eq!(
        _choices_0_finish_reason.to_string().as_str().trim(),
        r#"stop"#,
        "equals assertion failed"
    );
    assert_eq!(
        result.model.to_string().as_str().trim(),
        r#"claude-3-5-sonnet-20241022"#,
        "equals assertion failed"
    );
    assert_eq!(
        result.usage.as_ref().unwrap().total_tokens,
        23,
        "equals assertion failed"
    );
}

