#[tokio::test]
async fn test_bedrock_chat() {
    // Basic chat completion via the AWS Bedrock provider using the bedrock/ prefix for routing — verifies the prefix is stripped before dispatching and the Converse API response is normalised to the standard OpenAI chat completion shape
    let mock_route = MockRoute {
        path: "/chat/completions",
        method: "POST",
        status: 200,
        body: r#"{"choices":[{"finish_reason":"stop","index":0,"message":{"content":"Hello!","role":"assistant"}}],"created":1711000300,"id":"chatcmpl-bedrock-001","model":"anthropic.claude-3-sonnet-20240229-v1:0","object":"chat.completion","usage":{"completion_tokens":3,"prompt_tokens":12,"total_tokens":15}}"#.to_string(),
        is_streaming: false,
        stream_chunks: vec![],
        headers: vec![
        ],
        delay_ms: None,
    };
    let mock_server = MockServer::start(vec![mock_route]).await;
    let request_json: serde_json::Value = serde_json::from_str(r#"{"max_tokens":16,"messages":[{"content":"Say hello in one word.","role":"user"}],"model":"bedrock/anthropic.claude-3-sonnet-20240229-v1:0","temperature":0}"#).unwrap();
    let request = serde_json::from_value(request_json).unwrap();
    let client =
        liter_llm::create_client("test-key".to_string(), Some(mock_server.url.clone()), None, None, None).unwrap();
    let result = client.chat(request).await.expect("should succeed");
    let _choices_0_message_content = result.choices[0]
        .message
        .content
        .as_ref()
        .map(|v| v.to_string())
        .unwrap_or_default();
    let _choices_0_finish_reason = result.choices[0]
        .finish_reason
        .as_ref()
        .map(|v| v.to_string())
        .unwrap_or_default();
    assert_eq!(
        result.choices.len(),
        1,
        "expected exactly 1 elements, got {}",
        result.choices.len()
    );
    assert_eq!(
        _choices_0_message_content.to_string().as_str().trim(),
        r#"Hello!"#,
        "equals assertion failed"
    );
    assert_eq!(
        _choices_0_finish_reason.to_string().as_str().trim(),
        r#"stop"#,
        "equals assertion failed"
    );
    assert_eq!(
        result.model.to_string().as_str().trim(),
        r#"anthropic.claude-3-sonnet-20240229-v1:0"#,
        "equals assertion failed"
    );
    assert_eq!(
        result.usage.as_ref().unwrap().total_tokens,
        15,
        "equals assertion failed"
    );
}

